const onErr = (fallback) => (e) => {
  e.currentTarget.src = fallback;
  e.currentTarget.onerror = null;
};

// Tries multiple local paths; if one 404s, moves to the next
function MultiSrcImage({ sources = [], alt = '', fallback, imgClass = '', ...rest }) {
  const [idx, setIdx] = useState(0);
  const src = sources[idx] || fallback;
  return (
    <img
      src={src}
      alt={alt}
      onError={() => {
        if (idx + 1 < sources.length) setIdx(idx + 1);
        else if (fallback) {
          // let native onError handle fallback via rest.onError if provided
        }
      }}
      className={imgClass}
      {...rest}
    />
  );
}

