export default function Home() {
  const navigate = useNavigate();
  const [user, setUser] = useState(null);
  const [cats, setCats] = useState([]);
  const [openCart, setOpenCart] = useState(false);
  const [cart, setCart] = useState({ items: [] });
  const [items, setItems] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const { slug } = useParams();
  const [toast, setToast] = useState(null);
  const showToast = (msg) => { setToast(msg); setTimeout(() => setToast(null), 2000); };

  async function handleAddToCart(itemId, qty = 1) {
    try {
      await api.post("/cart", { itemId, qty });
      const crt = await api.get("/cart");
      setCart(crt.data || { items: [] });
      showToast("Added to cart");
    } catch (e) {
      console.error("Add to cart failed", e);
      alert("Failed to add to cart");
    }
  }

  async function handleSave(itemId) {
    try {
      await api.post(`/saved/${itemId}`);
      showToast('Saved');
    } catch (e) {
      console.error('Save failed', e);
      alert('Failed to save');
    }
  }

  async function handleOrderNow() {
    try {
      if (items && items.length > 0) {
        await handleAddToCart(items[0]._id, 1);
        setOpenCart(true);
      } else {
        navigate('/veg');
      }
    } catch (e) {
      console.error('Order Now failed', e);
      navigate('/home/category/veg');
    }
  }

  useEffect(() => {
    const fetchData = async () => {
      try {
        const meRes = await api.get("/auth/me").catch(() => ({ data: null }));
        if (!meRes.data?.user) {
          navigate("/", { replace: true });
          return;
        }
        setUser(meRes.data.user);

        const cartRes = await api.get("/cart").catch(() => ({ data: { items: [] } }));
        setCart(cartRes.data || { items: [] });

        if (slug) {
          const itemsRes = await api
            .get(`/items?category=${encodeURIComponent(slug)}`)
            .catch(() => ({ data: [] }));
          setItems(itemsRes.data || []);
        } else {
          const catsRes = await api.get("/items/categories").catch(() => ({ data: [] }));
          setCats(catsRes.data || []);
        }
      } catch (err) {
        console.error("Home load error:", err);
        setError("Failed to load data. Please try again.");
        if (err.response?.status === 401) {
          try { localStorage.removeItem("token"); } catch {}
          navigate("/", { replace: true });
        }
      } finally {
        setLoading(false);
      }
    };

    fetchData();
  }, [navigate, slug]);

  async function handleRemoveFromCart(itemId) {
    try {
      await api.delete(`/cart/${itemId}`);
      const crt = await api.get('/cart');
      setCart(crt.data || { items: [] });
    } catch (e) {
      console.error('Remove from cart failed', e);
    }
  }

  const total = useMemo(() => {
    return (cart.items || []).reduce((sum, item) => {
      const price = item.itemId?.price ?? 0;
      const qty = item.qty ?? 0;
      return sum + price * qty;
    }, 0);
  }, [cart.items]);

  if (loading) {
    return (
      <div className="min-h-screen bg-gray-50">
        <Header user={null} />
        <div className="max-w-6xl mx-auto p-3">
          <div className="animate-pulse">
            <div className="h-8 bg-gray-200 rounded w-48 mb-4" />
            <div className="h-64 bg-gray-200 rounded mb-6" />
            <div className="grid grid-cols-2 md:grid-cols-5 gap-4">
              {[...Array(5)].map((_, i) => (
                <div key={i} className="border rounded p-4">
                  <div className="h-12 bg-gray-200 rounded mx-auto mb-2" />
                  <div className="h-4 bg-gray-200 rounded w-20 mx-auto" />
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="text-center p-6">
          <p className="text-red-600 mb-4">{error}</p>
          <button onClick={() => window.location.reload()} className="px-4 py-2 bg-blue-600 text-white rounded hover:bg-blue-700">
            Retry
          </button>
        </div>
      </div>
    );
  }

  // Candidate filenames for each category under /images
  const CANDIDATES = {
    veg: [
      "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRzixsradRdo4yDXi4qY5nPGYvnRBBVb1GlhA&s", "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRzixsradRdo4yDXi4qY5nPGYvnRBBVb1GlhA&s", "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRzixsradRdo4yDXi4qY5nPGYvnRBBVb1GlhA&s",
      "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRzixsradRdo4yDXi4qY5nPGYvnRBBVb1GlhA&s", "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRzixsradRdo4yDXi4qY5nPGYvnRBBVb1GlhA&s"
    ],
    nonveg: [
      "data:image/jpeg;base64,", "/images/nonveg.jpeg", "/images/nonveg.png",
      "data:image/jpeg;base64,", "/images/chicken.jpg", "/images/nonveg1.jpg"
    ],
    seafood: [
      "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcSOxDuR86uRSJxnxIsvX9vDU7VZzTtym5xB6g&s", "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcSOxDuR86uRSJxnxIsvX9vDU7VZzTtym5xB6g&s", "/images/seafood.png",
      "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcSOxDuR86uRSJxnxIsvX9vDU7VZzTtym5xB6g&s", "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcSOxDuR86uRSJxnxIsvX9vDU7VZzTtym5xB6g&s", "/images/seafood1.jpg"
    ],
    chinese: [
      "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcQhsaUK0Cmuep0DEzeogFrWu451s2_eCBJJQA&s", "/images/chinese.jpeg", "/images/chinese.png",
      "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcQhsaUK0Cmuep0DEzeogFrWu451s2_eCBJJQA&s", "/images/chinese1.jpg"
    ],

  };

  // Thumbnails (all with images)
  const thumbs = [CANDIDATES.veg, CANDIDATES.nonveg, CANDIDATES.seafood, CANDIDATES.chinese];
  const isVegSlug = slug === 'veg';

  return (
    <div className="bg-gray-50">
      {/* Header */}
      <header className="bg-orange-500 text-white border-t-8 border-orange-600">
        <div className="max-w-6xl mx-auto px-4 h-14 flex items-center justify-between">
          <div className="logo border rounded p-2">
            <Link to="/">
              <img src={IMG.logo} onError={onErr(FALL.logo)} alt="Logo" className="h-10 w-auto" />
            </Link>
          </div>
          <div className="ml-3 text-lg font-bold">Tasty Trails</div>

          <nav className="hidden sm:flex items-center gap-4 ml-auto mr-4">
            <Link to="/home" className="px-3 py-1.5 rounded-full hover:bg-white/10">Home</Link>
            <Link to="/saved" className="px-3 py-1.5 rounded-full hover:bg-white/10">Saved</Link>
            <Link to="/profile" className="px-3 py-1.5 rounded-full hover:bg-white/10">Profile</Link>
          </nav>

          <button
            onClick={() => { try { localStorage.removeItem("token"); } catch {}; window.location.href = "/"; }}
            className="px-3 py-1.5 bg-white text-orange-700 rounded-full hover:bg-orange-50"
          >
            Log out
          </button>
        </div>
      </header>

      <div className="max-w-6xl mx-auto p-4">
        {/* Hero */}
        <section className="mt-4 bg-white rounded-2xl shadow-sm overflow-hidden">
          <div className="grid grid-cols-1 lg:grid-cols-4">
            <div className="p-6 lg:p-8 flex flex-col justify-center lg:col-span-1">
              <p className="text-green-600 font-semibold">Fresh • Healthy • Delightful</p>
              <h1 className="mt-3 text-4xl sm:text-5xl font-extrabold leading-tight text-gray-900">Tasty Trails</h1>
              <p className="mt-4 text-gray-600 max-w-xl">
                Discover delicious meals crafted with the freshest ingredients. Pick your favorite cuisines and get them delivered fast.
              </p>
              <div className="mt-6 flex items-center gap-3">
                <button onClick={handleOrderNow} className="inline-flex items-center px-5 py-3 rounded-full bg-green-600 text-white font-semibold hover:bg-green-700 transition-colors">
                  Order Now
                </button>
                <a href="#categories" className="inline-flex items-center px-5 py-3 rounded-full border border-green-200 text-green-700 hover:bg-green-50">
                  Explore Menu
                </a>
              </div>

              {/* Round thumbnails (all with images) */}
              <div className="mt-8 grid grid-cols-4 gap-4 max-w-md">
                {thumbs.map((sources, i) => (
                  <div key={i} className="aspect-square rounded-full overflow-hidden ring-1 ring-gray-200 bg-white grid place-items-center">
                    <MultiSrcImage
                      sources={sources}
                      fallback={[FALL.veg, FALL.nonveg, FALL.seafood, FALL.chinese][i]}
                      alt="thumb"
                      imgClass="w-full h-full object-cover"
                      referrerPolicy="no-referrer"
                    />
                  </div>
                ))}
              </div>
            </div>

            {/* Hero image */}
            <div className="relative bg-gray-50 lg:col-span-3">
              <img src={IMG.hero} onError={onErr(FALL.hero)} referrerPolicy="no-referrer" alt="Hero" className="w-full max-h-[480px] md:max-h-[520px] object-contain" />
            </div>
          </div>
        </section>

        {/* Choose a Category (all with images) */}
        <section id="categories" className="mt-6">
          <div className="text-2xl font-bold mb-4">Choose a Category</div>
          <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
            {/* Veg with image */}
            <Link to="/veg" className="group border rounded-lg overflow-hidden hover:shadow-lg transition-shadow bg-white"> <div className="h-40 overflow-hidden">
                <MultiSrcImage sources={CANDIDATES.veg} fallback={FALL.veg} referrerPolicy="no-referrer" alt="Veg Food" imgClass="w-full h-full object-cover" />
              </div>
              <div className="text-center p-1.5 font-medium">Veg</div>
            </Link>

            {/* Non-Veg with image */}
            <Link to="/non-veg" className="group border rounded-lg overflow-hidden hover:shadow-lg transition-shadow bg-white">
              <div className="h-40 overflow-hidden">
                <MultiSrcImage sources={CANDIDATES.nonveg} fallback={FALL.nonveg} referrerPolicy="no-referrer" alt="Non-Veg Food" imgClass="w-full h-full object-cover" />
              </div>
              <div className="text-center p-2 font-medium">Non-Veg</div>
            </Link>

            {/* Sea Food with image */}
            <Link to="/seafood" className="group border rounded-lg overflow-hidden hover:shadow-lg transition-shadow bg-white">
              <div className="h-40 overflow-hidden">
                <MultiSrcImage sources={CANDIDATES.seafood} fallback={FALL.seafood} referrerPolicy="no-referrer" alt="Sea Food" imgClass="w-full h-full object-cover" />
              </div>
              <div className="text-center p-2 font-medium">Sea Food</div>
            </Link>

            {/* Chinese with image */}
            <Link to="/chinese" className="group border rounded-lg overflow-hidden hover:shadow-lg transition-shadow bg-white">
              <div className="h-40 overflow-hidden">
                <MultiSrcImage sources={CANDIDATES.chinese} fallback={FALL.chinese} referrerPolicy="no-referrer" alt="Chinese Food" imgClass="w-full h-full object-cover" />
              </div>
              <div className="text-center p-2 font-medium">Chinese Food</div>
            </Link>
          </div>
        </section>

        {/* Heading + Cart */}
        <div className="flex justify-between items-center mb-3">
          {slug ? (
            <div className="flex items-center gap-3">
              <Link to="/" className="px-3 py-2 border rounded hover:bg-gray-50">Back</Link>
              <h2 className="text-2xl font-bold text-gray-800">
                {slug.replace(/-/g, " ").replace(/\b\w/g, (c) => c.toUpperCase())}
              </h2>
              {(cart.items?.length ?? 0) > 0 && (
                <span className="ml-1 bg-red-500 text-white text-xs rounded-full h-5 w-5 flex items-center justify-center">
                  {cart.items.length}
                </span>
              )}
            </div>
          ) : (
            <div />
          )}

          <button
            onClick={() => setOpenCart(true)}
            className="flex items-center gap-2 px-4 py-2 bg-[#ffad33] text-white rounded-lg hover:bg-[#ffa31a] transition-colors border border-[#ffad33]"
            aria-label={`Open cart with ${cart.items?.length || 0} items`}
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 3h2l.4 2M7 13h10l4-8H5.4m0 0L7 13m0 0v6m0-6l-2-5m2 5h10m-5 4a1 1 0 100-2 1 1 0 000 2z" />
            </svg>
            <span className="hidden sm:inline">Cart</span>
            {(cart.items?.length ?? 0) > 0 && (
              <span className="ml-1 bg-red-500 text-white text-xs rounded-full h-5 w-5 flex items-center justify-center">
                {cart.items.length}
              </span>
            )}
          </button>
        </div>

        {/* Home-only video hero */}
        {!slug && <VideoHero />}

        {/* Veg/Non‑Veg/Sea Food/Chinese image grids or fallback items */}
        {slug && (
          ["veg", "non-veg", "seafood", "chinese"].includes(slug) ? (
            <section className="mt-6 bg-blue-50 rounded-xl p-4 sm:p-6">
              <div className="flex items-center justify-between mb-4">
                <Link to="/home" className="text-blue-700 hover:underline">← Back</Link>
                <h1 className="text-3xl font-extrabold text-gray-900 text-center flex-1 -ml-10">
                  {slug.replace(/-/g, " ").replace(/\b\w/g, (c) => c.toUpperCase())} Varieties
                </h1>
                <div className="w-3" />
              </div>
              <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-6">
                {(slug === "veg" ? VEGS : slug === "non-veg" ? NONVEG : slug === "seafood" ? SEAFOODS : CHINESE).map((v, i) => (
                  <div key={i} className="bg-white rounded-xl shadow-sm border border-[#ffad33] hover:shadow-md transition-shadow">
                    <div className="aspect-video rounded-t-xl overflow-hidden">
                      {isVegSlug ? (
                        <MultiSrcImage
                          sources={[
                            `/images/veg/${v.name.toLowerCase().replace(/[^a-z0-9]+/g,'-').replace(/(^-|-$)/g,'')}.jpg`,
                            `/images/veg/${v.name.toLowerCase().replace(/[^a-z0-9]+/g,'-').replace(/(^-|-$)/g,'')}.jpeg`,
                            `/images/veg/${v.name.toLowerCase().replace(/[^a-z0-9]+/g,'-').replace(/(^-|-$)/g,'')}.png`
                          ]}
                          fallback={v.img}
                          alt={v.name}
                          imgClass="w-full h-full object-cover"
                          referrerPolicy="no-referrer"
                        />
                      ) : (
                        <img src={v.img} alt={v.name} referrerPolicy="no-referrer" onError={onErr(FALL.placeholder)} className="w-full h-full object-cover" />
                      )}
                    </div>
                    <div className="p-3">
                      <div className="font-semibold text-gray-900">{v.name}</div>
                      <p className="text-sm text-gray-600 mt-1">{v.desc}</p>
                    </div>
                  </div>
                ))}
              </div>
            </section>
          ) : (
            <div className="grid grid-cols-1 sm:grid-cols-2 lg-grid-cols-3 gap-6 mt-6">
              {items.map((it) => (
                <div key={it._id} className="border rounded-xl p-4 bg-white hover:shadow-md transition-shadow">
                  <Link to={`/items/${it._id}`} className="block">
                    <div className="aspect-video bg-gray-100 rounded mb-3 overflow-hidden">
                      <img src={it.image || FALL.placeholder} onError={onErr(FALL.placeholder)} alt={it.name} className="w-full h-full object-cover" />
                    </div>
                    <div className="font-semibold">{it.name}</div>
                    <div className="text-gray-600 text-sm line-clamp-2">{it.description}</div>
                    <div className="mt-2 font-medium">₹{it.price}</div>
                  </Link>
                  <div className="mt-3 grid grid-cols-2 gap-2">
                    <button onClick={() => handleAddToCart(it._id, 1)} className="px-3 py-2 bg-green-600 text-white rounded hover:bg-green-700">Add to Cart</button>
                    <button onClick={() => handleSave(it._id)} className="px-3 py-2 border rounded hover:bg-gray-50">Save</button>
                  </div>
                </div>
              ))}
              {items.length === 0 && <div className="text-gray-600">No items found for this category.</div>}
            </div>
          )
        )}
      </div>

      <CartDrawer open={openCart} onClose={() => setOpenCart(false)} items={cart.items || []} total={total} onRemove={handleRemoveFromCart} />
      {toast && (
        <div className="fixed bottom-4 left-1/2 -translate-x-1/2 bg-black text-white text-sm px-4 py-2 rounded shadow">
          {toast}
        </div>
      )}
    </div>
  );
}